#include &lt;stddef.h&gt; #include &lt;stdio.h&gt; char *maze_runner(const int *maze, size_t n, const char *directions) { if (maze == NULL || directions == NULL || n == 0) { return &#34;Dead&#34;; } int x = 0, y = 0; int found = 0; for (int i = 0; i &lt; n; i++) { for (int j = 0; j &lt; n; j++) { if (*(maze + j * n + i) == 2) { x = i; y = j; found = 1; break; } } if (found) { break; } } if (!found) { return &#34;Dead&#34;; } const char* ptr = directions; while (*ptr != &#39;\0&#39;) { switch (*ptr) { case &#39;N&#39;: y--; break; case &#39;S&#39;: y++; break; case &#39;W&#39;: x--; break; case &#39;E&#39;: x++; break; default: return &#34;Dead&#34;; } // 边界检查 if (x &lt; 0 || x &gt;= n || y &lt; 0 || y &gt;= n) { return &#34;Dead&#34;; } int cell_value = *(maze + y * n + x); if (cell_value == 1) { return &#34;Dead&#34;; } else if (cell_value == 3) { return &#34;Finish&#34;; } ptr++; } return &#34;Lost&#34;; } 一个简洁的解答 对于字符串 可以直接使用字符本身是否有效判断其是否结束 这个解答使用了directions[i] 作为for的循环判断
对于这个循环结构终止的判断有两种写法，循环第一次执行时，初值都是directions
\[1\] for for (size_t i = 0; directions[i]; i++) { //... } while：这个更简洁 while (directions) { //... directions++ } #include &lt;stddef.h&gt; #include &lt;iso646.h&gt; #define NORTH &#39;N&#39; #define SOUTH &#39;S&#39; #define EAST &#39;E&#39; #define WEST &#39;W&#39; #define START 2 #define WALL 1 #define FINISH 3 char *maze_runner(const int *maze, size_t n, const char *directions) { size_t x, y; for (size_t i = 0; i &lt; n; i++){ for (size_t j = 0; j &lt; n; j++) if (maze[i * n + j] == START){ x = j; y = i; } } for (size_t i = 0; directions[i]; i++){ x += (directions[i] == EAST) - (directions[i] == WEST); y += (directions[i] == SOUTH) - (directions[i] == NORTH); if (maze[y * n + x] == WALL or x &gt;= n or y &gt;= n) return &#34;Dead&#34;; if (maze[y * n + x] == FINISH) return &#34;Finish&#34;; } return &#34;Lost&#34;; }

