#include &lt;stddef.h&gt; size_t get_count(const char *s) { int count = 0; while(*s){ if(*s == &#39;a&#39; || *s == &#39;e&#39; || *s == &#39;i&#39; || *s == &#39;o&#39; || *s == &#39;u&#39;) count++; s++; } return count; } 最佳实践： 更为精妙 首先对空指针做了判断!s，避免异常 其次对字符串的遍历是用while(*s)的方式，*s++指针自增，直到遇到字符串结束符'\0',循环停止
#include &lt;stddef.h&gt; size_t get_count(const char *s) { size_t cnt = 0ul; if (!s) return 0ul; while (*s) switch (*s++) { case &#39;a&#39;: case &#39;e&#39;: case &#39;i&#39;: case &#39;o&#39;: case &#39;u&#39;: ++cnt; break; } return cnt; } 题目3：统计笑脸 # 给定一个数组（arr）作为参数，完成函数 countSmileys，该函数应返回笑脸的总数。 笑脸的规则：
每个笑脸必须包含一对有效的眼睛。眼睛可以用 : 或 ; 表示。 笑脸可以有鼻子，但不一定有。鼻子的有效字符是 - 或 ~。 每个笑脸都必须有一个微笑的嘴巴，应该用 ) 或 D 表示。 除了提到的字符外，不允许有其他字符。 有效的笑脸示例： :) :D ;-D :~)
无效的笑脸： ;( :&gt; :} :]
我的解答： 分支结构，可读性一般
#include &lt;stddef.h&gt; size_t count_smileys(size_t length, const char *const array[length]) { size_t count = 0; const char *str; if(length &gt; 0){ while(length --) { str = array[length]; printf(&#34;%s\n&#34;, str); if(*str == &#39;:&#39; || *str == &#39;;&#39;) { if(*(str+1)==&#39;-&#39; || *(str+1)==&#39;~&#39;) { if(*(str+2)==&#39;)&#39; || *(str+2)==&#39;D&#39;) count++; } else if(*(str+1)==&#39;)&#39; || *(str+1)==&#39;D&#39;) count++; } } } return count; } 函数解答（可读性好）：
#include &lt;stddef.h&gt; // chain: checkEye -&gt; checkNose -&gt; checkMouse -&gt; checkNull // chain: checkEye -&gt; checkMouse -&gt; checkNull int checkSmiley(const char* const p) { return checkEye(p); } int checkEye(const char* const p) { return (*p == &#39;:&#39; || *p == &#39;;&#39;) ? checkMouse(p + 1) || checkNose(p + 1) : 0; } int checkNose(const char* const p) { return (*p == &#39;-&#39; || *p == &#39;~&#39;) ? checkMouse(p + 1) : 0; } int checkMouse(const char* const p) { return (*p == &#39;)&#39; || *p == &#39;D&#39;) ? checkNull(p + 1) : 0; } int checkNull(const char* const p) { return (*p == &#39;\0&#39;) ? 1 : 0; } size_t count_smileys(size_t length, const char *const array[length]) { size_t n = 0; for(size_t i = 0; i &lt; length; i++){ // printf(&#34;%s\n&#34;, array[i]); n += checkSmiley(array[i]); } return n; } 库函数暴力解答：
#include &lt;stddef.h&gt; #include &lt;regex.h&gt; size_t count_smileys(size_t length, const char *const array[length]) { regex_t reg; regcomp(&amp;reg, &#34;[:;][-~]?[D)]&#34;, REG_EXTENDED); int match = 0; for (size_t i = 0; i &lt; length; ++i) if (regexec(&amp;reg, array[i], 0, NULL, 0) == 0) ++match; return match; } 库函数暴力解答2：
#include &lt;stddef.h&gt; #include &lt;string.h&gt; size_t count_smileys(size_t length, const char *const array[length]) { size_t smileys = 0; for (size_t i = 0; i &lt; length; i++) { smileys += strstr(&#34;:) :D :-) :-D :~) :~D ;) ;D ;-) ;-D ;~) ;~D&#34;, array[i]) != NULL; } return smileys; }

